+fn centered_window(selected: usize, total: usize, rows: usize) -> (usize, usize) {
+    if total == 0 {
+        return (0, 0);
+    }
+    let rows = rows.max(1).min(total);
+    let start = selected
+        .saturating_sub(rows / 2)
